package com.langfunda;
//Integral Literlas:Integer,Long Literlas
public class IntegralLiterals {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		      //Integer decimal literals
				int a=100;
				int b=23456;
				 
				//long decimal literals
				long a1=100000000000L;
				long a2=47548788884L;
				System.out.println(a);
				System.out.println(b);
				
				System.out.println(a1);
				System.out.println(a2);
				
				//Integer octal literals
				int c=0123;
				int d=0345;
				int f=05673;
				
				//Long octal Literlas
				long c1=0123456L;
				long c2=034674L;
		        
				System.out.println(c);
				System.out.println(d);
				System.out.println(f);
				
				System.out.println(c1);
				System.out.println(c2);
				
				//Integer hexa_decimal literals
				int x=0x123;
				int y=0xa23b;
				int z=0xcdef;
				
				//Long hexa-decimal literals
				long x1=0x26734337L;
				long x2=0x74748788449L;
				
				System.out.println(x);
				System.out.println(y);
				System.out.println(z);
				
				System.out.println(x1);
				System.out.println(x2);
				
				
				//Integer binary literals
				int p=0b101;
				int q=0b00110;
				
				//long binary literlas
				long p1=0b1010011000000111;
				long p2=0b1001000100010000;
				
				System.out.println(p);
				System.out.println(q);
				
				System.out.println(p1);
				System.out.println(p2);

	}

}
